16	/// Smoke test: assemble a trivial COR24 program, run it, verify register value.
17	fn emulator_smoke_test() -> Result<String, String> {
18	    let mut asm = Assembler::new();
19	    let result = asm.assemble("  lc r0, 42\nhalt:\n  bra halt\n");
20	    if !result.errors.is_empty() {
21	        return Err(format!("Assembly errors: {:?}", result.errors));
22	    }
23	
24	    let mut emu = EmulatorCore::new();
25	    emu.load_program(0, &result.bytes);
26	    emu.set_pc(0);
27	    emu.resume();
28	    let batch = emu.run_batch(100);
29	
30	    if !matches!(batch.reason, StopReason::Halted) {
31	        return Err(format!("Expected Halted, got {:?}", batch.reason));
32	    }
33	
34	    let r0 = emu.get_reg(0);
35	    if r0 == 42 {
36	        Ok(format!(
37	            "WASM smoke test PASSED: r0={r0}, {} instructions, halted OK",
38	            batch.instructions_run
39	        ))
40	    } else {
41	        Err(format!("Expected r0=42, got r0={r0}"))
42	    }
43	}
