45	/// Format a large number with K/M suffix for display.
46	fn format_count(n: u64) -> String {
47	    if n >= 1_000_000 {
48	        format!("{:.1}M", n as f64 / 1_000_000.0)
49	    } else if n >= 1_000 {
50	        format!("{:.1}K", n as f64 / 1_000.0)
51	    } else {
52	        n.to_string()
53	    }
54	}
