1	//! PL/SW compiler pipeline running on the COR24 emulator.
2	//!
3	//! The PL/SW compiler is a C program cross-compiled to COR24 assembly.
4	//! It runs on the emulator: source code enters via UART RX, output
5	//! exits via UART TX.  Currently the compiler implements lexer + parser
6	//! self-tests followed by a tokenizer REPL.
7	
8	use std::collections::VecDeque;
9	
10	use cor24_emulator::{Assembler, EmulatorCore, StopReason};
11	
12	/// Embedded PL/SW compiler assembly source (from sibling project build).
13	const COMPILER_ASM: &str = include_str!(env!("PLSW_COMPILER_PATH"));
14	
15	/// Maximum instructions to run during self-test boot phase.
16	const BOOT_LIMIT: u64 = 50_000_000;
17	
18	/// Instructions per batch when feeding input.
19	const FEED_BATCH: u64 = 100_000;
20	
21	/// Maximum total instructions for a compilation run.
22	const COMPILE_LIMIT: u64 = 200_000_000;
23	
24	/// Result of running the compiler pipeline.
25	#[derive(Clone, Debug, PartialEq)]
26	pub struct CompileResult {
27	    /// Self-test output from the compiler boot phase.
28	    pub boot_output: String,
29	    /// Compiler output for the user's source (token dump from REPL).
30	    pub compiler_output: String,
31	    /// Total instructions executed.
32	    pub instructions: u64,
33	    /// Whether the compiler halted (vs hit instruction limit).
34	    pub halted: bool,
35	    /// Error message if something went wrong.
36	    pub error: Option<String>,
37	}
38	
39	/// Assemble the PL/SW compiler, boot it on the emulator, feed source code,
40	/// and capture output.
41	pub fn run_compiler(source: &str, macro_sources: &[(String, String)]) -> CompileResult {
42	    // Step 1: Assemble the compiler .s to binary
43	    let mut asm = Assembler::new();
44	    let asm_result = asm.assemble(COMPILER_ASM);
45	    if !asm_result.errors.is_empty() {
46	        return CompileResult {
47	            boot_output: String::new(),
48	            compiler_output: String::new(),
49	            instructions: 0,
50	            halted: false,
51	            error: Some(format!(
52	                "Compiler assembly failed:\n{}",
53	                asm_result.errors.join("\n")
54	            )),
55	        };
56	    }
57	
58	    // Step 2: Load compiler into emulator
59	    let mut emu = EmulatorCore::new();
60	    emu.set_uart_tx_busy_cycles(0); // No TX delay in WASM
61	    emu.load_program(0, &asm_result.bytes);
62	    emu.load_program_extent(asm_result.bytes.len() as u32);
63	    emu.set_pc(0);
64	    emu.resume();
65	
66	    // Step 3: Run self-tests (boot phase) until we see the REPL prompt "> "
67	    let mut total_instructions: u64 = 0;
68	    let mut boot_output = String::new();
69	
70	    loop {
71	        let result = emu.run_batch(FEED_BATCH);
72	        total_instructions += result.instructions_run;
73	        collect_uart(&mut emu, &mut boot_output);
74	
75	        if matches!(result.reason, StopReason::Halted) {
76	            return CompileResult {
77	                boot_output,
78	                compiler_output: String::new(),
79	                instructions: total_instructions,
80	                halted: true,
81	                error: Some("Compiler halted during self-tests".into()),
82	            };
83	        }
84	
85	        // Check for REPL prompt
86	        if boot_output.ends_with("> ") {
87	            break;
88	        }
89	
90	        if total_instructions >= BOOT_LIMIT {
91	            return CompileResult {
92	                boot_output,
93	                compiler_output: String::new(),
94	                instructions: total_instructions,
95	                halted: false,
96	                error: Some(format!(
97	                    "Compiler boot exceeded {BOOT_LIMIT} instructions without reaching REPL"
98	                )),
99	            };
100	        }
101	    }
102	
103	    // Step 4: Build input -- prepend macro files, then source
104	    let mut input = String::new();
105	    for (name, macro_src) in macro_sources {
106	        input.push_str(&format!("/* --- {name} --- */\n"));
107	        input.push_str(macro_src);
108	        if !macro_src.ends_with('\n') {
109	            input.push('\n');
110	        }
111	    }
112	    input.push_str(source);
113	    if !source.ends_with('\n') {
114	        input.push('\n');
115	    }
116	
117	    // Step 5: Feed input via UART RX and capture output
118	    let mut rx_queue: VecDeque<u8> = input.bytes().collect();
119	    let mut compiler_output = String::new();
120	
121	    loop {
122	        // Feed bytes while UART RX is ready
123	        feed_uart_bytes(&mut emu, &mut rx_queue);
124	
125	        let result = emu.run_batch(FEED_BATCH);
126	        total_instructions += result.instructions_run;
127	        collect_uart(&mut emu, &mut compiler_output);
128	
129	        if matches!(result.reason, StopReason::Halted) {
130	            return CompileResult {
131	                boot_output,
132	                compiler_output: strip_echo(&compiler_output),
133	                instructions: total_instructions,
134	                halted: true,
135	                error: None,
136	            };
137	        }
138	
139	        // If all input consumed and output contains a fresh prompt, we're done
140	        if rx_queue.is_empty() && compiler_output.contains("> ") {
141	            // Check if the last prompt has no pending input
142	            // (output may contain multiple "> " from multi-line input)
143	            if compiler_output.ends_with("> ") {
144	                break;
145	            }
146	        }
147	
148	        if total_instructions >= COMPILE_LIMIT {
149	            return CompileResult {
150	                boot_output,
151	                compiler_output: strip_echo(&compiler_output),
152	                instructions: total_instructions,
153	                halted: false,
154	                error: Some("Compilation exceeded instruction limit".into()),
155	            };
156	        }
157	    }
158	
159	    CompileResult {
160	        boot_output,
161	        compiler_output: strip_echo(&compiler_output),
162	        instructions: total_instructions,
163	        halted: false,
164	        error: None,
165	    }
166	}
167	
168	/// Feed as many bytes as possible from the queue while UART RX is ready.
169	fn feed_uart_bytes(emu: &mut EmulatorCore, queue: &mut VecDeque<u8>) {
170	    while !queue.is_empty() {
171	        let status = emu.read_byte(0xFF0101);
172	        if status & 0x01 != 0 {
173	            break; // RX buffer full, try again next batch
174	        }
175	        if let Some(byte) = queue.pop_front() {
176	            emu.send_uart_byte(byte);
177	        }
178	    }
179	}
180	
181	/// Collect UART TX output into string buffer.
182	fn collect_uart(emu: &mut EmulatorCore, buf: &mut String) {
183	    let output = emu.get_uart_output();
184	    if !output.is_empty() {
185	        buf.push_str(output);
186	        emu.clear_uart_output();
187	    }
188	}
189	
190	/// Strip echoed input characters from compiler output.
191	///
192	/// The REPL echoes each typed character back, interleaved with token output.
193	/// We extract just the token lines (indented with spaces) and prompts.
194	fn strip_echo(raw: &str) -> String {
195	    let mut result = String::new();
196	    let mut in_prompt = false;
197	
198	    for line in raw.split('\n') {
199	        // Skip the echo of the prompt itself
200	        if line == "> " || line.starts_with("> ") {
201	            in_prompt = true;
202	            // Start of a new REPL interaction -- add separator
203	            if !result.is_empty() && !result.ends_with('\n') {
204	                result.push('\n');
205	            }
206	            continue;
207	        }
208	
209	        if in_prompt {
210	            // Lines starting with spaces are token output
211	            if line.starts_with("  ") {
212	                result.push_str(line.trim());
213	                result.push('\n');
214	            }
215	            // Other lines might be echoed chars or other output
216	        }
217	    }
218	
219	    result
220	}
221

