1	//! Wizard sidebar with progressive disclosure steps.
2	//!
3	//! Follows the cor24-rs wizard pattern: step indicators in column 2,
4	//! with an action button that advances to the next step.
5	
6	use yew::prelude::*;
7	
8	/// Pipeline steps for progressive disclosure.
9	#[derive(Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
10	pub enum WizardStep {
11	    Source,
12	    Macros,
13	    Preprocess,
14	    Compile,
15	    Assemble,
16	    Run,
17	}
18	
19	impl WizardStep {
20	    pub fn label(&self) -> &'static str {
21	        match self {
22	            Self::Source => "Source",
23	            Self::Macros => "Macros",
24	            Self::Preprocess => "Preprocess",
25	            Self::Compile => "Compile",
26	            Self::Assemble => "Assemble",
27	            Self::Run => "Run",
28	        }
29	    }
30	
31	    pub fn tooltip(&self) -> &'static str {
32	        match self {
33	            Self::Source => "Edit PL/SW source (.plsw)",
34	            Self::Macros => "Edit macro files (.msw)",
35	            Self::Preprocess => "Expand macros and includes",
36	            Self::Compile => "Compile PL/SW to COR24 assembly",
37	            Self::Assemble => "Assemble to machine code",
38	            Self::Run => "Execute and debug",
39	        }
40	    }
41	
42	    pub fn action_label(&self) -> &'static str {
43	        match self {
44	            Self::Source => "Edit Macros",
45	            Self::Macros => "Preprocess",
46	            Self::Preprocess => "Compile",
47	            Self::Compile => "Assemble",
48	            Self::Assemble => "Run",
49	            Self::Run => "",
50	        }
51	    }
52	
53	    pub fn next(&self) -> Option<WizardStep> {
54	        match self {
55	            Self::Source => Some(Self::Macros),
56	            Self::Macros => Some(Self::Preprocess),
57	            Self::Preprocess => Some(Self::Compile),
58	            Self::Compile => Some(Self::Assemble),
59	            Self::Assemble => Some(Self::Run),
60	            Self::Run => None,
61	        }
62	    }
63	
64	    pub fn cell_id(&self) -> &'static str {
65	        match self {
66	            Self::Source => "cell-source",
67	            Self::Macros => "cell-macros",
68	            Self::Preprocess => "cell-preprocess",
69	            Self::Compile => "cell-compile",
70	            Self::Assemble => "cell-assemble",
71	            Self::Run => "cell-run",
72	        }
73	    }
74	
75	    const ALL: [WizardStep; 6] = [
76	        Self::Source,
77	        Self::Macros,
78	        Self::Preprocess,
79	        Self::Compile,
80	        Self::Assemble,
81	        Self::Run,
82	    ];
83	}
84	
85	#[derive(Properties, PartialEq)]
86	pub struct WizardSidebarProps {
87	    pub current_step: WizardStep,
88	    pub on_step_click: Callback<WizardStep>,
89	    pub on_advance: Callback<()>,
90	    pub has_source: bool,
91	}
92	
93	/// Wizard step indicators column (column 2 of the 3-column layout).
94	#[function_component(WizardSidebar)]
95	pub fn wizard_sidebar(props: &WizardSidebarProps) -> Html {
96	    let on_step_click = props.on_step_click.clone();
97	
98	    html! {
99	        <div class="wizard-steps">
100	            { for WizardStep::ALL.iter().map(|&step| {
101	                let is_completed = props.has_source && step <= props.current_step;
102	                let is_active = step == props.current_step;
103	                let is_disabled = step > props.current_step;
104	
105	                let class = classes!(
106	                    "wizard-step",
107	                    is_active.then_some("active"),
108	                    is_completed.then_some("completed"),
109	                    is_disabled.then_some("disabled"),
110	                );
111	
112	                let indicator = if is_completed && !is_active { "\u{2713}" } else { "\u{25cb}" };
113	
114	                let onclick = if !is_disabled {
115	                    let cb = on_step_click.clone();
116	                    Some(Callback::from(move |_: MouseEvent| cb.emit(step)))
117	                } else {
118	                    None
119	                };
120	
121	                html! {
122	                    <div class={class} {onclick} data-tooltip={step.tooltip()}>
123	                        <span class="step-indicator">{indicator}</span>
124	                        <span class="step-label">{step.label()}</span>
125	                    </div>
126	                }
127	            })}
