                                    if !result.compiler_output.is_empty() {
                                        <pre class="pipeline-output">{&result.compiler_output}</pre>
                                    } else if result.error.is_none() {
                                        <div class="compile-status">
                                            <span>{"No token output (source may be empty)"}</span>
                                        </div>
