                    if *current_step >= WizardStep::Run {
                        <div class="notebook-cell" id="cell-run">
                            <div class="cell-header">
                                <span>{"Execution / Debugger"}</span>
                            </div>
                            <div class="cell-content">
                                <div class="notebook-placeholder">
                                    <span>{"Debugger -- coming soon"}</span>
                                </div>
                            </div>
                        </div>
