                    // Pipeline note
                    <div class="pipeline-note">
                        <em>{"Pipeline: .plsw + .msw \u{2192} Preprocess \u{2192} Compile (on COR24) \u{2192} .s \u{2192} Assemble \u{2192} Run"}</em>
                    </div>
                </div>
            </div>
            // Footer
            <footer>
                <span>{"MIT License"}</span>
                <span class="footer-sep">{"\u{00b7}"}</span>
